$(document).ready(function(){var url=window.location.href;var pathname=window.location.pathname;var segments=pathname.split("/").filter(function(segment){return segment !=="";});var firstParam=segments[0];console.log("URL:",url);console.log("Path segments:",segments);console.log("First parameter:",firstParam);var var_north=` <div id="radio-live-listen-block"><a href="https: `;var var_eastcentral=` <div id="radio-live-listen-block"><a href="https: `;var var_southwest=` <div id="radio-live-listen-block"><a href="https: `;var var_southeast=` <div id="radio-live-listen-block"><a href="https: `;var htmlToInsert="";switch(firstParam){case "north": htmlToInsert=var_north;break;case "saskatoon-today": htmlToInsert=var_north;break;case "central": htmlToInsert=var_eastcentral;break;case "southwest": htmlToInsert=var_southwest;break;case "southeast": htmlToInsert=var_southeast;break;case "regina-today": htmlToInsert=var_southwest;break;default: console.log("No matching region found for:",firstParam);return;}var heading='<h2 class="title mb-1">Tune In for Great Music!</h2>';htmlToInsert=heading+htmlToInsert;var checkExist=setInterval(function(){var $pollDiv=$(".widget.widget-poll");var $firstGAM=$(".widget-area-col.col-md-4 .widget.widget-dfp.gam").first();if($pollDiv.length > 0){$pollDiv.before(htmlToInsert);console.log("Custom HTML inserted before .widget-poll div for region:",firstParam);clearInterval(checkExist);}else if($firstGAM.length > 0){console.log("Found the first widget widget");$firstGAM.after(htmlToInsert);clearInterval(checkExist);}else{console.log("Widget not found.");}},300);});